lines = BlueRidge.Common.Util.extractQualifiedValues(value) or []
state = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.state) or {}
editDraft = state.get('editDraft') or {}
status = editDraft.get('status') or ''
if status == 'Draft':
	mode = 'draft'
elif status == 'Deprecated':
	mode = 'deprecated'
else:
	mode = 'published'
avail = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.availableItems) or []
uoms = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.uoms) or []
total = len(lines)
out = []
for i, ln in enumerate(lines):
	ln = ln or {}
	out.append({'line': ln, 'rowIndex': i, 'mode': mode, 'lineCount': total, 'availableItems': avail, 'uoms': uoms})
return out

customMethods.script:
itemId = self.view.params.value
self.view.custom.activeVersionId = None
self.view.custom.state = {"selected": self._emptyBom(), "editDraft": self._emptyBom()}
if not itemId:
	return
versions = BlueRidge.Parts.Bom.listByParentItem(itemId, self.view.custom.includeDeprecated) or []
if versions:
	self.view.custom.activeVersionId = versions[0].get("Id")

bomId = self.view.custom.activeVersionId
if not bomId:
	self.view.custom.state = {"selected": self._emptyBom(), "editDraft": self._emptyBom()}
	return
bundle = BlueRidge.Parts.Bom.getOneFull(bomId)
self.view.custom.state = {"selected": bundle, "editDraft": self._cloneBundle(bundle)}

return {
	"id": None, "parentItemId": None, "versionNumber": None,
	"effectiveFrom": None, "effectiveFromDisplay": "",
	"publishedAt": None, "deprecatedAt": None,
	"status": None, "lines": [],
}

draft = self.view.custom.state.editDraft or {}
draftId = draft.get("id")
draftVer = draft.get("versionNumber")
if not draftId:
	return
priorVer = None
for v in (self.view.custom.versions or []):
	if not v:
		continue
	if v.get("Id") == draftId:
		continue
	if (v.get("Status") or "") == "Published":
		priorVer = v.get("VersionNumber")
		break
if priorVer is None:
	self.handlePublish()
	return
msg = "Publish v" + str(draftVer) + "? This will deprecate v" + str(priorVer) + " (currently active in production)."
system.perspective.openPopup(
	id="mpp-confirm-destructive",
	view="BlueRidge/Components/Popups/ConfirmDestructive",
	modal=True,
	showCloseIcon=False,
	params={
		"title":        "Publish BOM",
		"message":      msg,
		"confirmLabel": "Publish",
		"cancelLabel":  "Cancel",
		"confirmClass": "btn btn-primary btn-sm",
		"replyMessage": "bomConfirmPublishResult",
	},
)

