messageHandlers.script:
if not payload:
	return
if payload.get("action") != "confirm":
	return
self.handlePublish()

if not payload:
	return
if payload.get("action") != "confirm":
	return
sel = self.view.custom.state.selected or {}
bomId = sel.get("id")
if not bomId:
	return
result = BlueRidge.Parts.Bom.handleDeprecate(bomId)
BlueRidge.Common.Ui.notifyResult(result, "BOM deprecated")
if result and result.get("Status"):
	self.refreshVersionList()
	self.loadActiveVersion()

if not payload:
	return
if payload.get("action") != "confirm":
	return
draft = self.view.custom.state.editDraft or {}
bomId = draft.get("id")
if not bomId:
	return
result = BlueRidge.Parts.Bom.handleDiscardDraft(bomId)
BlueRidge.Common.Ui.notifyResult(result, "Draft discarded")
if result and result.get("Status"):
	self.view.custom.activeVersionId = None
	self.refreshVersionList()
	vers = self.view.custom.versions or []
	if vers:
		self.view.custom.activeVersionId = vers[0].get("Id")
